import sys

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def recoverTree(self, root: TreeNode) -> TreeNode:
        def inorder(root):
            return inorder(root.left) + [root.val] + inorder(root.right) if root else []

        def recover(root, nodes):
            if root:
                recover(root.left, nodes)
                root.val = nodes.pop(0)
                recover(root.right, nodes)

        nodes = sorted(inorder(root))
        recover(root, nodes)
        return root

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        root = TreeNode()
        stack = [root]
        for _ in range(n):
            val = int(next(it))
            node = TreeNode(val)
            if stack[-1].val == 0:
                stack[-1].val = val
            elif stack[-1].left is None:
                stack[-1].left = node
                stack.append(node)
            else:
                stack[-1].right = node
                stack.pop()
                while stack and stack[-1].right is not None:
                    stack.pop()
        sol = Solution()
        ans = sol.recoverTree(root)
        def preorder(root):
            return [root.val] + preorder(root.left) + preorder(root.right) if root else []
        print(' '.join(map(str, preorder(root))))
    except StopIteration:
        sys.exit(0)

