#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode() : val(0), left(nullptr), right(nullptr) {}
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
};

class Solution {
public:
    TreeNode* recoverTree(TreeNode* root) {
        vector<int> nodes;
        inorder(root, nodes);
        sort(nodes.begin(), nodes.end());
        recover(root, nodes);
        return root;
    }

private:
    void inorder(TreeNode* root, vector<int>& nodes) {
        if (root) {
            inorder(root->left, nodes);
            nodes.push_back(root->val);
            inorder(root->right, nodes);
        }
    }

    void recover(TreeNode* root, vector<int>& nodes) {
        if (root) {
            recover(root->left, nodes);
            root->val = nodes.front();
            nodes.erase(nodes.begin());
            recover(root->right, nodes);
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    TreeNode* root = new TreeNode();
    stack<TreeNode*> stack;
    stack.push(root);
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        TreeNode* node = new TreeNode(val);
        if (stack.top()->val == 0) {
            stack.top()->val = val;
        } else if (stack.top()->left == nullptr) {
            stack.top()->left = node;
            stack.push(node);
        } else {
            stack.top()->right = node;
            stack.pop();
            while (!stack.empty() && stack.top()->right != nullptr) {
                stack.pop();
            }
        }
    }
    Solution sol;
    TreeNode* ans = sol.recoverTree(root);
    function<void(TreeNode*)> preorder = [&](TreeNode* root) {
        if (root) {
            cout << root->val << ' ';
            preorder(root->left);
            preorder(root->right);
        }
    };
    preorder(ans);
    cout << '\n';
    return 0;
}
